72: 	if !o.scheme.IsGroupRegistered(resource.Group) {
73: 		return schema.GroupVersion{}, fmt.Errorf("group %q is not registered in scheme", resource.Group)
74: 	}
75: 
76: 	resourceOverride, resourceExists := o.resources[resource]
